      </section>
    </v-main>
  </v-app>
</template>

<script>
import MovieItem from "@/components/Movie/MovieItemC";
import axios from "axios";
import { mapActions, mapState } from "vuex";
export default {
  data: () => ({
    item: "",
    movieItem: "",
    similar: [],
    apiKey: "194d8a67379374e13e12c99420c19098",
    persons: [],
    dialog: false,
    movieYear: "",
    movieInFav: false,
    favorite: [],
    favoriteBtn: false,
    nomovie: false,
    loading: true,
    imageLength: "",
    castLength: "",
    attrs: {
      class: "mb-6",
      boilerplate: false,
      elevation: 2,
    },
    firstLoad: true,
    images: [],
    crews: [],
    video: "",
    genres: [],
  }),
  mounted() {
    // console.log("details", this.movieInFav);
    this.item = this.$route.params.item;
    this.getMovie();
    this.getSimilarMovie();
    this.getFavFromLocal();
    this.checkMovieIn();
  },
  methods: {
    async getSimilarMovie() {
      await this.$axios
        .get(
          `https://api.themoviedb.org/3/movie/${this.item}/similar?api_key=${this.$apiKey}&language=en-US&page=1`
        )
        .then((resp) => {
          this.similar = resp.data.results;
          // console.log(resp);
        })
        .catch((error) => {
          if (error) {
            // console.log("thats similar error", error);
            return;
          }
        });
    },
    async getMovie() {
      await axios
        .get(
          `https://api.themoviedb.org/3/movie/${this.item}?api_key=${this.apiKey}&append_to_response=credits,videos,images`
        )
        .then((resp) => {
          // console.log(resp);
          this.movieItem = resp.data;
          // console.log("movie item ", this.movieItem);
          this.persons = resp.data.credits.cast;
          this.images = resp.data.images;
          // console.log("data", resp.data);
          this.movieYear = this.movieItem.release_date.substr(0, 4);
          this.imageLength = this.images.backdrops.length;
          this.castLength = this.persons.length;
          // console.log(this.persons.length);
          this.crews = resp.data.credits.crew;
          if (resp.data.videos.results.length != 0) {
            this.video = resp.data.videos.results[0].key;
          }
          this.genres = resp.data.genres;
        })
        .catch((error) => {
          if (error) {
            // console.log("thats error", error);
            this.nomovie = true;
            // console.log("thats error", this.nomovie);
          }
        });
    },
    stopAllYouTubeVideos() {
      const videos = document.querySelectorAll("iframe");
      videos.forEach((i) => {
        const source = i.src;
        i.src = "";
        i.src = source;
      });
    },
    addToFavorite(movieId) {
      this.A_addToFavorite(movieId);
      this.movieInFav = this.S_movieInFav;
      // console.log("in add function", this.movieInFav);
    },
    getFavFromLocal() {
      if (localStorage.getItem("favorites")) {
        this.$store.state.movie.S_favorite = JSON.parse(
          localStorage.getItem("favorites")
        );
      }
    },
    checkMovieIn() {
      let IsMovieIn = this.$store.state.movie.S_favorite.find((el) => {
        return el == this.item;
      });
      if (IsMovieIn) {
        // console.log("yes it is in");
        this.movieInFav = true;
      } else {
        this.movieInFav = false;
        // console.log("nooooo");
      }
      // console.log(this.item);
      // console.log(this.$store.state.movie.S_favorite);
    },
    ...mapActions(["A_addToFavorite"]),
  },
  created() {
    const readyHandler = () => {
      if (document.readyState == "complete") {
        // console.log("completed");
        setTimeout(() => {
          this.firstLoad = false;
        }, 1500);
        document.removeEventListener("readystatechange", readyHandler);
      }
    };
    document.addEventListener("readystatechange", readyHandler);
    readyHandler();
  },
  updated() {
    // console.log("favorite", this.favorite);
  },
  components: {
    MovieItem,
  },
  computed: {
    ...mapState({
      S_favBtn: (store) => store.movie.S_favBtn,
      S_movieInFav: (store) => store.movie.S_movieInFav,
    }),
  },
};
</script>

